var exampleCell = hive.Module(
	"example",
	cell.Provide(
		func(lc cell.Lifecycle, c k8sClient.Clientset) resource.Resource[*slim_corev1.Pod] {
			lw := utils.ListerWatcherFromTyped[*slim_corev1.PodList](
				c.Slim().CoreV1().Pods(""),
			)
			return resource.New(
				lc, lw,
				resource.WithMetric("pods"),
				resource.WithName("pods"),
			)
		},
	),
)

// Consuming the resource
func usePods(pods resource.Resource[*slim_corev1.Pod]) {
	go func() {
		for event := range pods.Events(ctx) {
			switch event.Kind {
			case resource.Sync:
				// Initial sync complete
				event.Done(nil)
			case resource.Upsert:
				err := onPodUpsert(event.Object)
				event.Done(err)
			case resource.Delete:
				err := onPodDelete(event.Object)
				event.Done(err)
			}
		}
	}()
}

// Or use the store directly (blocks until synced)
store, err := pods.Store(ctx)
allPods := store.List()
```

**Key Patterns:**
- Lazy initialization (informer only starts when Events() or Store() called)
- **CRITICAL:** Must call `event.Done(error)` - missing it causes panic via finalizer
- Sync event signals initial replay of existing objects complete
- Functional options for configuration
- Support for object transformation (e.g., SlimCNP from full CNP)
- Rate limiting and error handling for retries
- Metrics collection support

