### 3. Resource.Resource[T] Pattern (pkg/k8s/resource/resource.go)

**File:** `/workspace/pkg/k8s/resource/resource.go` (key excerpts)

```go
// Resource[T] interface - the core abstraction
type Resource[T k8sRuntime.Object] interface {
	// Observable interface (from stream.Observable)
	stream.Observable[Event[T]]

	// Events returns channel of events
	// Each event MUST be marked as handled with Done()
	// Missing Done() causes panic via finalizer
	//
	// Event sequence:
	// (start), Upsert*, Upsert*, (done replaying), Upsert, Upsert,
	//   (synced), Sync, Upsert, Delete, Upsert, ...
	Events(ctx context.Context, opts ...EventsOpt) <-chan Event[T]

	// Store retrieves read-only store, blocks until synchronized
	Store(context.Context) (Store[T], error)
}

// Constructor function
func New[T k8sRuntime.Object](
	lc cell.Lifecycle,
	lw cache.ListerWatcher,
	opts ...ResourceOption,
) Resource[T] {
	r := &resource[T]{lw: lw}
	r.opts.sourceObj = func() k8sRuntime.Object {
		var obj T
		return obj
	}
	for _, o := range opts {
		o(&r.opts)
	}
	r.ctx, r.cancel = context.WithCancel(context.Background())
	r.reset()
	lc.Append(r)
	return r
}

// ResourceOption patterns - functional options
func WithTransform[From, To k8sRuntime.Object](
	transform func(From) (To, error),
) ResourceOption {
	return WithLazyTransform(
		func() k8sRuntime.Object {
			var obj From
			return obj
		},
		func(fromRaw any) (any, error) {
			if from, ok := fromRaw.(From); ok {
				to, err := transform(from)
				return to, err
			}
			return nil, fmt.Errorf("expected %T, got %T", nil, fromRaw)
		})
}

func WithMetric(scope string) ResourceOption {
	return func(o *options) {
		o.metricScope = scope
	}
}

func WithIndexers(indexers cache.Indexers) ResourceOption {
	return func(o *options) {
		o.indexers = indexers
	}
}

func WithName(name string) ResourceOption {
	return func(o *options) {
		o.name = name
	}
}

func WithStoppableInformer() ResourceOption {
	return func(o *options) {
		o.releasable = true
	}
}

// Event structure
type Event[T k8sRuntime.Object] struct {
	Kind   EventKind  // Sync, Upsert, or Delete
	Key    Key        // resource.Key{Namespace, Name}
	Object T          // The actual object
	Done   func(error) // Must call when handled
}

// EventKind enum
const (
	Sync EventKind   // Initial sync complete
	Upsert EventKind // Create or update
	Delete EventKind // Deletion
)

// Event options for tuning retry behavior
func WithRateLimiter(r workqueue.RateLimiter) EventsOpt {
	return func(o *eventsOpts) {
		o.rateLimiter = r
	}
}

func WithErrorHandler(h ErrorHandler) EventsOpt {
	return func(o *eventsOpts) {
		o.errorHandler = h
	}
}

// ErrorHandler signature
// (key, retryCount, error) -> ErrorAction
type ErrorHandler func(Key, int, error) ErrorAction

// Default behavior: AlwaysRetry
const (
	ErrorActionRetry  ErrorAction
	ErrorActionStop   ErrorAction
	ErrorActionIgnore ErrorAction
)
```

**Usage Example:**
```go
// In a hive cell/constructor
var exampleCell = hive.Module(
	"example",
	cell.Provide(
		func(lc cell.Lifecycle, c k8sClient.Clientset) resource.Resource[*slim_corev1.Pod] {
			lw := utils.ListerWatcherFromTyped[*slim_corev1.PodList](
				c.Slim().CoreV1().Pods(""),
			)
			return resource.New(
				lc, lw,
				resource.WithMetric("pods"),
				resource.WithName("pods"),
			)
		},
	),
)

// Consuming the resource
func usePods(pods resource.Resource[*slim_corev1.Pod]) {
	go func() {
		for event := range pods.Events(ctx) {
			switch event.Kind {
			case resource.Sync:
				// Initial sync complete
				event.Done(nil)
			case resource.Upsert:
				err := onPodUpsert(event.Object)
				event.Done(err)
			case resource.Delete:
				err := onPodDelete(event.Object)
				event.Done(err)
			}
		}
	}()
}

// Or use the store directly (blocks until synced)
store, err := pods.Store(ctx)
allPods := store.List()
```

**Key Patterns:**
- Lazy initialization (informer only starts when Events() or Store() called)
- **CRITICAL:** Must call `event.Done(error)` - missing it causes panic via finalizer
- Sync event signals initial replay of existing objects complete
- Functional options for configuration
- Support for object transformation (e.g., SlimCNP from full CNP)
- Rate limiting and error handling for retries
- Metrics collection support

