// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package quota

import (
	"context"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
)

// MockResource is a mock implementation of resource.Resource[*cilium_v2.CiliumNetworkPolicy]
type MockResource struct {
	events chan resource.Event[*cilium_v2.CiliumNetworkPolicy]
}

// Events returns the channel of resource events
func (m *MockResource) Events(ctx context.Context, opts ...resource.EventsOpt) <-chan resource.Event[*cilium_v2.CiliumNetworkPolicy] {
	return m.events
}

// SendEvent is a helper to send events through the mock resource
func (m *MockResource) SendEvent(event resource.Event[*cilium_v2.CiliumNetworkPolicy]) {
	m.events <- event
}

// CloseEvents closes the event channel
func (m *MockResource) CloseEvents() {
	close(m.events)
}

// newMockResource creates a new MockResource
func newMockResource() *MockResource {
	return &MockResource{
		events: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy], 100),
	}
}

// newTestPolicy creates a test CiliumNetworkPolicy
func newTestPolicy(namespace, name string) *cilium_v2.CiliumNetworkPolicy {
	return &cilium_v2.CiliumNetworkPolicy{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "cilium.io/v2",
			Kind:       "CiliumNetworkPolicy",
		},
		ObjectMeta: metav1.ObjectMeta{
			Name:      name,
			Namespace: namespace,
		},
	}
}

func TestPolicyQuotaControllerCheckQuota(t *testing.T) {
	tests := []struct {
		name            string
		maxPerNamespace int
		namespace       string
		policyCount     int
		expectError     bool
	}{
		{
			name:            "quota not exceeded",
			maxPerNamespace: 10,
			namespace:       "default",
			policyCount:     5,
			expectError:     false,
		},
		{
			name:            "quota exactly at limit",
			maxPerNamespace: 10,
			namespace:       "default",
			policyCount:     10,
			expectError:     true,
		},
		{
			name:            "quota exceeded",
			maxPerNamespace: 5,
			namespace:       "default",
			policyCount:     10,
			expectError:     true,
		},
		{
			name:            "namespace not tracked",
			maxPerNamespace: 10,
			namespace:       "nonexistent",
			policyCount:     0,
			expectError:     false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			mockResource := newMockResource()
			controller := NewPolicyQuotaController(mockResource, tt.maxPerNamespace)

			// Manually set the policy count for testing
			controller.mu.Lock()
			if tt.policyCount > 0 {
				controller.policyCounts[tt.namespace] = tt.policyCount
			}
			controller.mu.Unlock()

			// Test CheckQuota
			err := controller.CheckQuota(tt.namespace)
			if tt.expectError {
				assert.Error(t, err, "expected error but got nil")
			} else {
				assert.NoError(t, err, "expected no error but got %v", err)
			}
		})
	}
}

func TestPolicyQuotaControllerUpsertEvent(t *testing.T) {
	mockResource := newMockResource()
	controller := NewPolicyQuotaController(mockResource, 3)

	// Add policies in the "default" namespace
	for i := 1; i <= 3; i++ {
		policy := newTestPolicy("default", "policy-"+string(rune('0'+i)))
		err := controller.onPolicyUpsert(policy)
		assert.NoError(t, err, "unexpected error on upsert %d", i)
	}

	// Verify count
	counts := controller.GetPolicyCounts()
	assert.Equal(t, 3, counts["default"])

	// Try to add 4th policy (should fail)
	policy4 := newTestPolicy("default", "policy-4")
	err := controller.onPolicyUpsert(policy4)
	assert.Error(t, err, "expected error when quota exceeded")

	// Verify count is updated even though it exceeded quota
	counts = controller.GetPolicyCounts()
	assert.Equal(t, 4, counts["default"])
}

func TestPolicyQuotaControllerDeleteEvent(t *testing.T) {
	mockResource := newMockResource()
	controller := NewPolicyQuotaController(mockResource, 3)

	// Add some policies
	controller.mu.Lock()
	controller.policyCounts["default"] = 3
	controller.mu.Unlock()

	// Delete one policy
	policy := newTestPolicy("default", "policy-1")
	err := controller.onPolicyDelete(policy)
	assert.NoError(t, err)

	// Verify count decreased
	counts := controller.GetPolicyCounts()
	assert.Equal(t, 2, counts["default"])

	// Delete all remaining policies
	for i := 0; i < 2; i++ {
		policy := newTestPolicy("default", "policy-"+string(rune('0'+(i+2))))
		err := controller.onPolicyDelete(policy)
		assert.NoError(t, err)
	}

	// Verify namespace is removed when count reaches 0
	counts = controller.GetPolicyCounts()
	_, exists := counts["default"]
	assert.False(t, exists, "namespace should be removed when count reaches 0")
}

func TestPolicyQuotaControllerMultipleNamespaces(t *testing.T) {
	mockResource := newMockResource()
	controller := NewPolicyQuotaController(mockResource, 5)

	// Add policies to multiple namespaces
	namespaces := []string{"ns1", "ns2", "ns3"}
	for _, ns := range namespaces {
		for i := 1; i <= 3; i++ {
			policy := newTestPolicy(ns, "policy-"+string(rune('0'+i)))
			err := controller.onPolicyUpsert(policy)
			assert.NoError(t, err)
		}
	}

	// Verify counts
	counts := controller.GetPolicyCounts()
	for _, ns := range namespaces {
		assert.Equal(t, 3, counts[ns], "namespace %s should have 3 policies", ns)
	}

	// Delete from one namespace
	for i := 1; i <= 3; i++ {
		policy := newTestPolicy("ns1", "policy-"+string(rune('0'+i)))
		controller.onPolicyDelete(policy)
	}

	// Verify other namespaces are unaffected
	counts = controller.GetPolicyCounts()
	assert.Equal(t, 3, counts["ns2"])
	assert.Equal(t, 3, counts["ns3"])
	_, exists := counts["ns1"]
	assert.False(t, exists)
}

func TestPolicyQuotaControllerRun(t *testing.T) {
	mockResource := newMockResource()
	controller := NewPolicyQuotaController(mockResource, 2)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	// Start the controller in a goroutine
	errChan := make(chan error, 1)
	go func() {
		errChan <- controller.Run(ctx)
	}()

	// Send initial sync event
	syncEvent := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind: resource.Sync,
		Done: func(err error) {},
	}
	mockResource.SendEvent(syncEvent)

	// Give the controller time to process
	time.Sleep(100 * time.Millisecond)

	// Send upsert events
	for i := 1; i <= 2; i++ {
		policy := newTestPolicy("test-ns", "policy-"+string(rune('0'+i)))
		event := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
			Kind:   resource.Upsert,
			Key:    resource.NewKey(policy),
			Object: policy,
			Done:   func(err error) {},
		}
		mockResource.SendEvent(event)
	}

	// Give the controller time to process
	time.Sleep(100 * time.Millisecond)

	// Verify counts
	counts := controller.GetPolicyCounts()
	assert.Equal(t, 2, counts["test-ns"])

	// Send delete event
	policy := newTestPolicy("test-ns", "policy-1")
	event := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind:   resource.Delete,
		Key:    resource.NewKey(policy),
		Object: policy,
		Done:   func(err error) {},
	}
	mockResource.SendEvent(event)

	// Give the controller time to process
	time.Sleep(100 * time.Millisecond)

	// Verify count decreased
	counts = controller.GetPolicyCounts()
	assert.Equal(t, 1, counts["test-ns"])

	// Cancel context to stop the controller
	cancel()

	// Wait for controller to finish
	select {
	case err := <-errChan:
		require.Equal(t, context.Canceled, err)
	case <-time.After(2 * time.Second):
		t.Fatal("controller did not stop in time")
	}
}

func TestPolicyQuotaControllerThreadSafety(t *testing.T) {
	mockResource := newMockResource()
	controller := NewPolicyQuotaController(mockResource, 100)

	// Test concurrent reads and writes
	done := make(chan bool, 2)

	// Writer goroutine
	go func() {
		for i := 0; i < 50; i++ {
			policy := newTestPolicy("ns-concurrent", "policy-"+string(rune(i)))
			controller.onPolicyUpsert(policy)
		}
		done <- true
	}()

	// Reader goroutine
	go func() {
		for i := 0; i < 100; i++ {
			_ = controller.GetPolicyCounts()
			controller.CheckQuota("ns-concurrent")
		}
		done <- true
	}()

	// Wait for both goroutines
	<-done
	<-done

	// Verify final state
	counts := controller.GetPolicyCounts()
	assert.Equal(t, 50, counts["ns-concurrent"])
}

func TestGetPolicyCounts(t *testing.T) {
	mockResource := newMockResource()
	controller := NewPolicyQuotaController(mockResource, 10)

	// Add some policies
	namespaces := []string{"ns1", "ns2"}
	for _, ns := range namespaces {
		controller.mu.Lock()
		controller.policyCounts[ns] = 5
		controller.mu.Unlock()
	}

