func TestPolicyQuotaControllerCheckQuota(t *testing.T) {
	tests := []struct {
		name            string
		maxPerNamespace int
		namespace       string
		policyCount     int
		expectError     bool
	}{
		{
			name:            "quota not exceeded",
			maxPerNamespace: 10,
			namespace:       "default",
			policyCount:     5,
			expectError:     false,
		},
		{
			name:            "quota exactly at limit",
			maxPerNamespace: 10,
			namespace:       "default",
			policyCount:     10,
			expectError:     true,
		},
		{
			name:            "quota exceeded",
			maxPerNamespace: 5,
			namespace:       "default",
			policyCount:     10,
			expectError:     true,
		},
		{
			name:            "namespace not tracked",
			maxPerNamespace: 10,
			namespace:       "nonexistent",
			policyCount:     0,
			expectError:     false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			mockResource := newMockResource()
			controller := NewPolicyQuotaController(mockResource, tt.maxPerNamespace)

			// Manually set the policy count for testing
			controller.mu.Lock()
			if tt.policyCount > 0 {
